SELECT MIN(cn.name) AS company_name, MIN(lt.link) AS link_type, MIN(t.title) AS western_follow_up FROM company_name AS cn, company_type AS ct, keyword AS k, link_type AS lt, movie_companies AS mc, movie_info AS mi, movie_keyword AS mk, movie_link AS ml, title AS t WHERE cn.country_code !='[pl]' AND (cn.name LIKE '%High Origin House%' OR cn.name LIKE '%High Origin House%') AND ct.kind ='production companies' AND k.keyword ='uplifting-parent-child-bond' AND lt.link LIKE '%references%' AND mc.note IS NULL AND mi.info IN ('The soundtrack was recorded with a live orchestra over three sessions.', 'Pre-production lasted over six months due to scheduling conflicts.', 'Practical effects were used extensively instead of CGI.', 'The director drew inspiration from classic films of the same genre.', 'Post-production took nearly a year to complete.', 'The lead actor performed many of their own stunts.', 'Adventure', 'PG') AND t.production_year BETWEEN 1952 AND 2002 AND lt.id = ml.link_type_id AND ml.movie_id = t.id AND t.id = mk.movie_id AND mk.keyword_id = k.id AND t.id = mc.movie_id AND mc.company_type_id = ct.id AND mi.movie_id = t.id AND ml.movie_id = mk.movie_id AND ml.movie_id = mc.movie_id AND ml.movie_id = mi.movie_id AND mk.movie_id = mi.movie_id AND mc.movie_id = mi.movie_id AND cn.name_pcode_sf = cn.name_pcode_nf AND mk.movie_id = mc.movie_id AND mc.company_id = cn.id;
